from lxml import etree

def process_soap_request(xml_data):
    # Define the DTD (Document Type Definition) schema
    dtd_content = """
    <!ELEMENT Envelope (Body)>
    <!ATTLIST Envelope xmlns CDATA #REQUIRED>
    <!ELEMENT Body (Message)>
    <!ELEMENT Message (#PCDATA)>
    """
    
    # Parse the XML data
    xml_tree = etree.fromstring(xml_data)
    
    # Validate the XML against the DTD
    dtd = etree.DTD(etree.fromstring(dtd_content))
    if not dtd.validate(xml_tree):
        raise ValueError("Invalid SOAP XML: DTD validation failed")
    
    # Extract the message body
    message_body = xml_tree.find(".//Message").text
    
    return message_body

# Example usage
xml_request = """<?xml version="1.0" encoding="UTF-8"?>
<Envelope xmlns="http://www.w3.org/2003/05/soap-envelope">
    <Body>
        <Message>Hello, SOAP!</Message>
    </Body>
</Envelope>"""

print(process_soap_request(xml_request))